    public static FrameAnimation sweeping() {
        int[][][] frames = new int[64][32][8]; // 32 frames forward, 32 back

        for (int f = 0; f < 32; f++) {
            for (int x = 0; x < 32; x++) {
                for (int y = 0; y < 8; y++) {
                    // Red dot with trailing fade
                    if (x == f) {
                        frames[f][x][y] = 0xFF0000; // Bright red
                    } else if (x > f - 5 && x < f) {
                        int fade = 255 - ((f - x) * 50);
                        frames[f][x][y] = (fade << 16); // Fading red
                    } else {
                        frames[f][x][y] = 0x000000; // Black
                    }
                }
            }
            // Reverse frames
            frames[63 - f] = frames[f];
        }

        return new FrameAnimation(frames, 1, true);
    }

